#include "controller.h"

static bool controller_sensor_is_fresh(uint32_t now_ms, uint32_t last_sample_ms)
{
    return (now_ms - last_sample_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static void controller_set_filling(controller_t *controller)
{
    controller->inlet_open = true;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_FILLING;
}

static void controller_set_heating(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = true;
    controller->state = CONTROLLER_STATE_HEATING;
}

static void controller_set_holding(controller_t *controller, bool heater_on)
{
    controller->inlet_open = false;
    controller->heater_on = heater_on;
    controller->state = CONTROLLER_STATE_HOLDING;
}

static bool controller_has_fresh_sensors(const controller_t *controller, uint32_t now_ms)
{
    return controller->has_valid_temperature &&
           controller->has_valid_level &&
           controller_sensor_is_fresh(now_ms, controller->last_temperature_ms) &&
           controller_sensor_is_fresh(now_ms, controller->last_level_ms);
}

static void controller_apply_policy(controller_t *controller, uint32_t now_ms)
{
    const int level = controller->last_level;
    const int temperature = controller->last_temperature_c;
    const bool previous_heater_on = controller->heater_on;
    const bool temperature_rising = controller->has_valid_temperature &&
                                    (controller->last_temperature_c > controller->previous_temperature_c);

    if (!controller_has_fresh_sensors(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller_set_filling(controller);
        return;
    }

    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        controller_set_safe_idle(controller);
        return;
    }

    if (temperature > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller_set_safe_idle(controller);
        return;
    }

    if (temperature < CONTROLLER_TEMP_LOW_THRESHOLD) {
        controller_set_heating(controller);
        return;
    }

    if ((temperature >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) &&
        (temperature <= CONTROLLER_TEMP_HIGH_THRESHOLD) &&
        temperature_rising) {
        controller_set_holding(controller, false);
        return;
    }

    if ((temperature >= CONTROLLER_TEMP_LOW_THRESHOLD) &&
        (temperature < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD)) {
        controller_set_holding(controller, previous_heater_on);
        return;
    }

    if ((temperature >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) &&
        (temperature <= CONTROLLER_TEMP_HIGH_THRESHOLD)) {
        controller_set_holding(controller, previous_heater_on);
        return;
    }

    controller_set_safe_idle(controller);
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;
    bool reset_sensors = false;
    bool malformed_or_explicit_timeout = false;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->previous_temperature_c = controller->has_valid_temperature ? controller->last_temperature_c : input.temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        controller->has_valid_temperature = true;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        controller->has_valid_level = true;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        malformed_or_explicit_timeout = true;
        reset_sensors = true;
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        malformed_or_explicit_timeout = true;
        reset_sensors = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (reset_sensors) {
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
    }

    if (malformed_or_explicit_timeout) {
        controller_set_safe_idle(controller);
        output.timed_out = (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT);
    } else if (controller->has_valid_temperature && controller->has_valid_level) {
        controller_apply_policy(controller, input.now_ms);
    } else {
        controller_set_safe_idle(controller);
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

